14552   bool Changed = false;
14553 
14554   // If the target claims to have no vector registers don't attempt
14555   // vectorization.
14556   if (!TTI->getNumberOfRegisters(TTI->getRegisterClassForType(true))) {
14557     LLVM_DEBUG(
14558         dbgs() << "SLP: Didn't find any vector registers for target, abort.\n");
14559     return false;
14560   }
14561 
14562   // Don't vectorize when the attribute NoImplicitFloat is used.
14563   if (F.hasFnAttribute(Attribute::NoImplicitFloat))
14564     return false;
14565 
14566   LLVM_DEBUG(dbgs() << "SLP: Analyzing blocks in " << F.getName() << ".\n");
14567 
14568   // Use the bottom up slp vectorizer to construct chains that start with
14569   // store instructions.
14570   BoUpSLP R(&F, SE, TTI, TLI, AA, LI, DT, AC, DB, DL, ORE_);
14571 
14572   // A general note: the vectorizer must use BoUpSLP::eraseInstruction() to
14573   // delete instructions.
14574 
14575   // Update DFS numbers now so that we can use them for ordering.
14576   DT->updateDFSNumbers();
14577 
14578   // Scan the blocks in the function in post order.
14579   for (auto *BB : post_order(&F.getEntryBlock())) {
14580     // Start new block - clear the list of reduction roots.
14581     R.clearReductionData();
14582     collectSeedInstructions(BB);
14583 
14584     // Vectorize trees that end at stores.
14585     if (!Stores.empty()) {
14586       LLVM_DEBUG(dbgs() << "SLP: Found stores for " << Stores.size()
14587                         << " underlying objects.\n");
14588       Changed |= vectorizeStoreChains(R);
14589     }
14590 
14591     // Vectorize trees that end at reductions.
14592     Changed |= vectorizeChainsInBlock(BB, R);
14593 
14594     // Vectorize the index computations of getelementptr instructions. This
14595     // is primarily intended to catch gather-like idioms ending at
14596     // non-consecutive loads.
14597     if (!GEPs.empty()) {
14598       LLVM_DEBUG(dbgs() << "SLP: Found GEPs for " << GEPs.size()
14599                         << " underlying objects.\n");
14600       Changed |= vectorizeGEPIndices(BB, R);
14601     }
14602   }
14603 
14604   if (Changed) {
14605     R.optimizeGatherSequence();
14606     LLVM_DEBUG(dbgs() << "SLP: vectorized \"" << F.getName() << "\"\n");
14607   }
14608   return Changed;
14609 }
14610 
14611 bool SLPVectorizerPass::vectorizeStoreChain(ArrayRef<Value *> Chain, BoUpSLP &R,
14612                                             unsigned Idx, unsigned MinVF) {
14613   LLVM_DEBUG(dbgs() << "SLP: Analyzing a store chain of length " << Chain.size()
14614                     << "\n");
14615   const unsigned Sz = R.getVectorElementSize(Chain[0]);
14616   unsigned VF = Chain.size();
14617 
14618   if (!isPowerOf2_32(Sz) || !isPowerOf2_32(VF) || VF < 2 || VF < MinVF)
14619     return false;
14620 
14621   LLVM_DEBUG(dbgs() << "SLP: Analyzing " << VF << " stores at offset " << Idx
14622                     << "\n");
14623 
14624   R.buildTree(Chain);
14625   if (R.isTreeTinyAndNotFullyVectorizable())
14626     return false;
14627   if (R.isLoadCombineCandidate())
14628     return false;
14629   R.reorderTopToBottom();
14630   R.reorderBottomToTop();
14631   R.buildExternalUses();
14632 
14633   R.computeMinimumValueSizes();
14634 
14635   InstructionCost Cost = R.getTreeCost();
14636 
14637   LLVM_DEBUG(dbgs() << "SLP: Found cost = " << Cost << " for VF=" << VF << "\n");
14638   if (Cost < -SLPCostThreshold) {
14639     LLVM_DEBUG(dbgs() << "SLP: Decided to vectorize cost = " << Cost << "\n");
14640 
14641     using namespace ore;
14642 
14643     R.getORE()->emit(OptimizationRemark(SV_NAME, "StoresVectorized",
14644                                         cast<StoreInst>(Chain[0]))
14645                      << "Stores SLP vectorized with cost " << NV("Cost", Cost)
14646                      << " and with tree size "
14647                      << NV("TreeSize", R.getTreeSize()));
14648 
14649     R.vectorizeTree();
14650     return true;
14651   }
14652 
14653   return false;
14654 }
