14656 bool SLPVectorizerPass::vectorizeStores(ArrayRef<StoreInst *> Stores,
14657                                         BoUpSLP &R) {
14658   // We may run into multiple chains that merge into a single chain. We mark the
14659   // stores that we vectorized so that we don't visit the same store twice.
14660   BoUpSLP::ValueSet VectorizedStores;
