14664   // already tried to be vectorized. Allows to skip the store ranges that were
14665   // already tried to be vectorized but the attempts were unsuccessful.
14666   DenseSet<std::pair<Value *, Value *>> TriedSequences;
14667   struct StoreDistCompare {
14668     bool operator()(const std::pair<unsigned, int> &Op1,
14669                     const std::pair<unsigned, int> &Op2) const {
14670       return Op1.second < Op2.second;
14671     }
14672   };
