14676       std::set<std::pair<unsigned, int>, StoreDistCompare>;
14677   auto TryToVectorize = [&](const StoreIndexToDistSet &Set) {
14678     int PrevDist = -1;
14679     BoUpSLP::ValueList Operands;
14680     // Collect the chain into a list.
14681     for (auto [Idx, Data] : enumerate(Set)) {
14682       if (Operands.empty() || Data.second - PrevDist == 1) {
14683         Operands.push_back(Stores[Data.first]);
14684         PrevDist = Data.second;
14685         if (Idx != Set.size() - 1)
14686           continue;
14687       }
14688       auto E = make_scope_exit([&, &DataVar = Data]() {
14689         Operands.clear();
14690         Operands.push_back(Stores[DataVar.first]);
14691         PrevDist = DataVar.second;
14692       });
14693 
14694       if (Operands.size() <= 1)
14695         continue;
14696 
14697       unsigned MaxVecRegSize = R.getMaxVecRegSize();
14698       unsigned EltSize = R.getVectorElementSize(Operands[0]);
14699       unsigned MaxElts = llvm::bit_floor(MaxVecRegSize / EltSize);
14700 
14701       unsigned MaxVF =
14702           std::min(R.getMaximumVF(EltSize, Instruction::Store), MaxElts);
14703       auto *Store = cast<StoreInst>(Operands[0]);
14704       Type *StoreTy = Store->getValueOperand()->getType();
14705       Type *ValueTy = StoreTy;
14706       if (auto *Trunc = dyn_cast<TruncInst>(Store->getValueOperand()))
14707         ValueTy = Trunc->getSrcTy();
14708       unsigned MinVF = TTI->getStoreMinimumVF(
14709           R.getMinVF(DL->getTypeSizeInBits(ValueTy)), StoreTy, ValueTy);
14710 
14711       if (MaxVF < MinVF) {
14712         LLVM_DEBUG(dbgs() << "SLP: Vectorization infeasible as MaxVF (" << MaxVF
14713                           << ") < "
14714                           << "MinVF (" << MinVF << ")\n");
14715         continue;
14716       }
14717 
14718       unsigned Sz = 1 + Log2_32(MaxVF) - Log2_32(MinVF);
14719       SmallVector<unsigned> CandidateVFs(Sz);
